using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Probabilities { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly MLContext _mlContext;
    private readonly ILogger<ModelTrainingService> _logger;

    public ModelTrainingService(ILogger<ModelTrainingService> logger)
    {
        _mlContext = new MLContext(seed: 42);
        _logger = logger;
    }

    public string TrainAndSave(string dataPath, string modelPath)
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model from {DataPath}...", dataPath);
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        var report = $"""
            === Model Evaluation Metrics ===
            Macro Accuracy:    {metrics.MacroAccuracy:F4}
            Micro Accuracy:    {metrics.MicroAccuracy:F4}
            Log Loss:          {metrics.LogLoss:F4}
            Log Loss Reduction:{metrics.LogLossReduction:F4}
            """;

        _logger.LogInformation("{Metrics}", report);

        // Per-class metrics
        foreach (var cm in metrics.PerClassLogLoss.Select((loss, i) => new { Index = i, Loss = loss }))
        {
            _logger.LogInformation("  Class {Index} Log Loss: {Loss:F4}", cm.Index, cm.Loss);
        }

        _mlContext.Model.Save(model, data.Schema, modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return report;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;

    private static readonly string[] Categories = ["Billing", "General", "Technical"];

    public TicketsController(PredictionEnginePool<TicketData, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var probabilities = Categories
            .Zip(prediction.Score)
            .ToDictionary(pair => pair.First, pair => pair.Second);

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Probabilities = probabilities
        });
    }

    [HttpPost("retrain")]
    public ActionResult<string> Retrain([FromServices] ModelTrainingService trainingService)
    {
        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
        var report = trainingService.TrainAndSave(dataPath, modelPath);
        return Ok(report);
    }
}

